            const landStart2 = Math.max(landStartTime[i], waterEnd2);
            const landEnd2 = landStart2 + landDuration[i];
            const totalTime2 = landEnd2;

            // Update minTime with the minimum of the two cases
            minTime = Math.min(minTime, totalTime1, totalTime2);
        }
    }

    return minTime;
}
